import React, { useState } from 'react';

module 2: create the table component with sorting and filtering functionality  
const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [sortField, setSortField] = useState('name');
    const [sortOrder, setSortOrder] = useState('asc');
    const [filter, setFilter] = useState('');

    const filteredRecords = records.filter(record => {
        const lowerName = record.name.toLowerCase();
        return lowerName.includes(filter.toLowerCase());
    });

    const sortedRecords = [...filteredRecords].sort((a, b) => {
        if (sortOrder === 'asc') return a[sortField] - b[sortField];
        else return b[sortField] - a[sortField];
    });

    const handleSort = (field) => {
        setSortField(field);
        setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    };

    const handleFilter = (e) => {
        setFilter(e.target.value);
    };

    return (
        <div>
            <table>
                <thead>
                    <tr>
                        <th onClick={() => handleSort('id')}>id</th>
                        <th onClick={() => handleSort('name')}>name</th>
                        <th onClick={() => handleSort('age')}>age</th>
                    </tr>
                </thead>
                <tbody>
                    {sortedRecords.map(record => (
                        <tr key={record.id}>
                            <td>{record.id}</td>
                            <td>{record.name}</td>
                            <td>{record.age}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
            <input type="text" placeholder="filter by name" onChange={handleFilter} />
        </div>
    );
};

